+    #[test]
+    fn request_builder_sets_fields() {
+        let peer_addr: SocketAddr = "10.0.0.9:9000".parse().unwrap();
+        let req = Request::builder(Method::Patch, "/v1/items/7")
+            .version(Version::Http10)
